import { Room } from "matrix-js-sdk/src/models/room";
import { Thread } from "matrix-js-sdk/src/models/thread";
import { MatrixEvent } from "matrix-js-sdk/src/models/event";
import { EventType } from "matrix-js-sdk/src/@types/event";
import { M_BEACON } from "matrix-js-sdk/src/@types/beacon";

import { MatrixClientPeg } from "./MatrixClientPeg";
import shouldHideEvent from "./shouldHideEvent";
import { haveRendererForEvent } from "./events/EventTileFactory";
import SettingsStore from "./settings/SettingsStore";

/**
 * Returns true if this event arriving in a room should affect the room's
 * count of unread messages
 *
 * @param {Object} ev The event
 * @returns {boolean} True if the given event should affect the unread message count
 */
export function eventTriggersUnreadCount(ev: MatrixEvent): boolean {
    if (ev.getSender() === MatrixClientPeg.get().credentials.userId) {
        return false;
    }

    switch (ev.getType()) {
        case EventType.RoomMember:
        case EventType.RoomThirdPartyInvite:
        case EventType.CallAnswer:
        case EventType.CallHangup:
        case EventType.RoomCanonicalAlias:
        case EventType.RoomServerAcl:
        case M_BEACON.name:
        case M_BEACON.altName:
            return false;
    }

    if (ev.isRedacted()) return false;
    return haveRendererForEvent(ev, false /* hidden messages should never trigger unread counts anyways */);
}

/**
 * Determines whether a single timeline has unread messages after the given read-up-to ID.
 * If readUpToId is null/undefined, considers the timeline unread if it has any relevant events.
 * Does NOT count the last event as unread if it was sent by the current user.
 */
function timelineHasUnread(
    events: MatrixEvent[],
    readUpToId: string | null,
    myUserId: string,
): boolean {
    if (!events || events.length === 0) return false;

    // If the last relevant event was sent by the current user, do not consider unread
    // Find the last event that would trigger unread
    const lastRelevantEvent = [...events].reverse().find(
        (ev) => !shouldHideEvent(ev) && (ev.isRedacted() ? false : true),
    );
    if (lastRelevantEvent && lastRelevantEvent.getSender() === myUserId) {
        return false;
    }

    for (let i = events.length - 1; i >= 0; --i) {
        const ev = events[i];

        if (ev.getId() === readUpToId) {
            // The user has read up to this event - nothing is unread
            return false;
        } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
            // We found an unread message before hitting the read receipt
            return true;
        }
    }

    // Didn't find the read receipt - if there were no relevant events, not unread
    // If readUpToId was provided but not found, assume unread (false positive better than false negative)
    return readUpToId !== null && readUpToId !== undefined
        ? true // receipt exists but points to an event not in our local history - assume unread
        : events.some((ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev));
}

export function doesRoomHaveUnreadMessages(room: Room): boolean {
    if (SettingsStore.getValue("feature_sliding_sync")) {
        // TODO: https://github.com/vector-im/element-web/issues/23207
        // Sliding Sync doesn't support unread indicator dots (yet...)
        return false;
    }

    const myUserId = MatrixClientPeg.get().getUserId();

    // Check the main room timeline
    const mainTimelineEvents = room.timeline || [];

    // Get read receipt for main timeline
    const mainReadUpToId = room.getEventReadUpTo(myUserId);

    // Special case: if the last event on the main timeline was sent by the current user,
    // don't count it as unread (we can't send read receipts for our own events)
    const mainTimelineLength = mainTimelineEvents.length;
    if (
        mainTimelineLength > 0 &&
        mainTimelineEvents[mainTimelineLength - 1].getSender() === myUserId
    ) {
        // Check if there are any threads with unread messages
        const threads = room.getThreads ? room.getThreads() : [];
        for (const thread of threads) {
            const threadEvents = thread.timeline || [];
            const threadReadUpToId = room.getEventReadUpTo
                ? (() => {
                      // Try to get thread-specific read receipt
                      try {
                          return (thread as any).getEventReadUpTo?.(myUserId) ??
                              room.getEventReadUpTo(myUserId, false);
                      } catch {
                          return room.getEventReadUpTo(myUserId);
                      }
                  })()
                : null;

            if (timelineHasUnread(threadEvents, threadReadUpToId, myUserId)) {
                return true;
            }
        }
        return false;
    }

    // Check if the main read receipt points to a thread event
    // In that case, the main timeline may still have unread messages
    const receiptEvent = mainReadUpToId ? room.findEventById(mainReadUpToId) : null;
    const receiptIsInThread = receiptEvent?.getThread?.() != null;

    // Check the main room timeline for unread messages
    // If the receipt is in a thread, use null so we scan the full main timeline
    const mainTimeline = room.timeline;
    let mainHasUnread = false;

    if (!receiptIsInThread) {
        // Normal main timeline check
        for (let i = mainTimeline.length - 1; i >= 0; --i) {
            const ev = mainTimeline[i];

            if (ev.getId() === mainReadUpToId) {
                mainHasUnread = false;
                break;
            } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
                mainHasUnread = true;
                break;
            }
        }

        // If we didn't find the read receipt, check if there are events that count
        if (mainReadUpToId && !mainHasUnread) {
            // If we didn't hit the receipt, it might be before our local history
            // In that case, check if there are any counting events
            const hasCountingEvents = mainTimeline.some(
                (ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev),
            );
            mainHasUnread = hasCountingEvents && !mainTimeline.some((ev) => ev.getId() === mainReadUpToId);
        } else if (!mainReadUpToId) {
            // No read receipt at all - check for any events
            mainHasUnread = mainTimeline.some((ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev));
        }
    } else {
        // Receipt is in a thread - check the main timeline for any unread events
        // (Since the receipt is thread-specific, all main-timeline events might be unread)
        mainHasUnread = mainTimeline.some((ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev));
    }

    if (mainHasUnread) return true;

    // Now check all threads
    const threads = room.getThreads ? room.getThreads() : [];
    for (const thread of threads) {
        const threadTimeline = thread.timeline || [];

        // Get the thread-specific read receipt
        // Threads track their own read receipts
        let threadReadUpToId: string | null = null;
        try {
            threadReadUpToId = (thread as any).getEventReadUpTo?.(myUserId) ?? null;
        } catch {
            threadReadUpToId = null;
        }

        // If no thread-specific receipt, try the room receipt to see if it's for this thread
        if (!threadReadUpToId && receiptIsInThread && receiptEvent?.getThread?.()?.id === thread.id) {
            threadReadUpToId = mainReadUpToId;
        }

        // Check if the last event in the thread was sent by the current user
        const lastThreadEvent = threadTimeline[threadTimeline.length - 1];
        if (lastThreadEvent?.getSender() === myUserId) {
            continue;
        }

        for (let i = threadTimeline.length - 1; i >= 0; --i) {
            const ev = threadTimeline[i];

            if (ev.getId() === threadReadUpToId) {
                break; // Thread is read up to here
            } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
                return true; // Found unread in thread
            }
        }

        // If we have no thread receipt and there are events that count, it's unread
        if (!threadReadUpToId && threadTimeline.some((ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev))) {
            return true;
        }
    }

    return false;
}

