133: export const mockGeolocation = (): MockedObject<Geolocation> => {
134:     const mockGeolocation = {
135:         clearWatch: jest.fn(),
136:         getCurrentPosition: jest.fn().mockImplementation((callback) => callback(makeGeolocationPosition({}))),
137:         watchPosition: jest.fn().mockImplementation((callback) => callback(makeGeolocationPosition({}))),
138:     } as unknown as MockedObject<Geolocation>;
