147: /**
148:  * Creates a mock watchPosition implementation
149:  * that calls success callback at the provided delays
150:  * ```
151:  * geolocation.watchPosition.mockImplementation([0, 1000, 5000, 50])
152:  * ```
153:  * will call the provided handler with a mock position at
154:  * next tick, 1000ms, 6000ms, 6050ms
155:  *
156:  * to produce errors provide an array of error codes
157:  * that will be applied to the delay with the same index
158:  * eg:
159:  * ```
160:  * // return two good positions, then a permission denied error
161:  * geolocation.watchPosition.mockImplementation(watchPositionMockImplementation(
162:  *      [0, 1000, 3000], [0, 0, 1]),
163:  * );
164:  * ```
165:  * See for error codes: https://developer.mozilla.org/en-US/docs/Web/API/GeolocationPositionError
166:  */
167: export const watchPositionMockImplementation = (delays: number[], errorCodes: number[] = []) => {
168:     return (callback: PositionCallback, error: PositionErrorCallback) => {
169:         const position = makeGeolocationPosition({});
170: 
171:         let totalDelay = 0;
172:         delays.map((delayMs, index) => {
173:             totalDelay += delayMs;
174:             const timeout = window.setTimeout(() => {
175:                 if (errorCodes[index]) {
176:                     error(getMockGeolocationPositionError(errorCodes[index], "error message"));
177:                 } else {
178:                     callback({ ...position, timestamp: position.timestamp + totalDelay });
179:                 }
180:             }, totalDelay);
181:             return timeout;
182:         });
183:     };
184: };
