201:             // this filtering happens in roomState, which is bypassed here
202:             const validLocationEvents = locationEvents?.filter((event) => event.getSender() === beacon.beaconInfoOwner);
203:             beacon.addLocations(validLocationEvents);
204:         });
205:     }
206:     return beacons;
207: };
