33: function weblateToCounterpart(inTrs: object): object {
34:     const outTrs = {};
35: 
36:     for (const key of Object.keys(inTrs)) {
37:         const keyParts = key.split("|", 2);
38:         if (keyParts.length === 2) {
39:             let obj = outTrs[keyParts[0]];
40:             if (obj === undefined) {
41:                 obj = outTrs[keyParts[0]] = {};
42:             } else if (typeof obj === "string") {
43:                 // This is a transitional edge case if a string went from singular to pluralised and both still remain
44:                 // in the translation json file. Use the singular translation as `other` and merge pluralisation atop.
45:                 obj = outTrs[keyParts[0]] = {
46:                     other: inTrs[key],
47:                 };
48:                 console.warn("Found entry in i18n file in both singular and pluralised form", keyParts[0]);
49:             }
50:             obj[keyParts[1]] = inTrs[key];
51:         } else {
52:             outTrs[key] = inTrs[key];
53:         }
54:     }
55: 
56:     return outTrs;
57: }
