20: import { ICreateClientOpts, PendingEventOrdering, RoomNameState, RoomNameType } from "matrix-js-sdk/src/matrix";
21: import { IStartClientOpts, MatrixClient } from "matrix-js-sdk/src/client";
22: import { MemoryStore } from "matrix-js-sdk/src/store/memory";
23: import * as utils from "matrix-js-sdk/src/utils";
24: import { EventTimeline } from "matrix-js-sdk/src/models/event-timeline";
25: import { EventTimelineSet } from "matrix-js-sdk/src/models/event-timeline-set";
26: import { verificationMethods } from "matrix-js-sdk/src/crypto";
27: import { SHOW_QR_CODE_METHOD } from "matrix-js-sdk/src/crypto/verification/QRCode";
28: import { logger } from "matrix-js-sdk/src/logger";
29: 
30: import createMatrixClient from "./utils/createMatrixClient";
31: import SettingsStore from "./settings/SettingsStore";
32: import MatrixActionCreators from "./actions/MatrixActionCreators";
33: import Modal from "./Modal";
34: import MatrixClientBackedSettingsHandler from "./settings/handlers/MatrixClientBackedSettingsHandler";
35: import * as StorageManager from "./utils/StorageManager";
36: import IdentityAuthClient from "./IdentityAuthClient";
37: import { crossSigningCallbacks, tryToUnlockSecretStorageWithDehydrationKey } from "./SecurityManager";
38: import SecurityCustomisations from "./customisations/Security";
39: import { SlidingSyncManager } from "./SlidingSyncManager";
40: import CryptoStoreTooNewDialog from "./components/views/dialogs/CryptoStoreTooNewDialog";
41: import { _t } from "./languageHandler";
