43: export interface IMatrixClientCreds {
44:     homeserverUrl: string;
45:     identityServerUrl?: string;
46:     userId: string;
47:     deviceId?: string;
48:     accessToken: string;
49:     guest?: boolean;
50:     pickleKey?: string;
51:     freshLogin?: boolean;
52: }
53: 
54: /**
55:  * Holds the current instance of the `MatrixClient` to use across the codebase.
56:  * Looking for an `MatrixClient`? Just look for the `MatrixClientPeg` on the peg
57:  * board. "Peg" is the literal meaning of something you hang something on. So
58:  * you'll find a `MatrixClient` hanging on the `MatrixClientPeg`.
59:  */
60: export interface IMatrixClientPeg {
61:     opts: IStartClientOpts;
62: 
63:     /**
64:      * Return the server name of the user's homeserver
65:      * Throws an error if unable to deduce the homeserver name
66:      * (eg. if the user is not logged in)
67:      *
68:      * @returns {string} The homeserver name, if present.
69:      */
70:     getHomeserverName(): string;
71: 
72:     get(): MatrixClient;
73:     unset(): void;
74:     assign(): Promise<any>;
75:     start(): Promise<any>;
76: 
77:     getCredentials(): IMatrixClientCreds;
78: 
79:     /**
80:      * If we've registered a user ID we set this to the ID of the
81:      * user we've just registered. If they then go & log in, we
82:      * can send them to the welcome user (obviously this doesn't
83:      * guarantee they'll get a chat with the welcome user).
84:      *
85:      * @param {string} uid The user ID of the user we've just registered
86:      */
87:     setJustRegisteredUserId(uid: string | null): void;
88: 
89:     /**
90:      * Returns true if the current user has just been registered by this
91:      * client as determined by setJustRegisteredUserId()
92:      *
93:      * @returns {bool} True if user has just been registered
94:      */
95:     currentUserIsJustRegistered(): boolean;
96: 
97:     /**
98:      * If the current user has been registered by this device then this
99:      * returns a boolean of whether it was within the last N hours given.
100:      */
101:     userRegisteredWithinLastHours(hours: number): boolean;
102: 
103:     /**
104:      * If the current user has been registered by this device then this
105:      * returns a boolean of whether it was after a given timestamp.
106:      */
107:     userRegisteredAfter(date: Date): boolean;
108: 
109:     /**
110:      * Replace this MatrixClientPeg's client with a client instance that has
111:      * homeserver / identity server URLs and active credentials
112:      *
113:      * @param {IMatrixClientCreds} creds The new credentials to use.
114:      */
115:     replaceUsingCreds(creds: IMatrixClientCreds): void;
116: }
117: 
118: /**
119:  * Wrapper object for handling the js-sdk Matrix Client object in the react-sdk
120:  * Handles the creation/initialisation of client objects.
121:  * This module provides a singleton instance of this class so the 'current'
122:  * Matrix Client object is available easily.
123:  */
124: class MatrixClientPegClass implements IMatrixClientPeg {
125:     // These are the default options used when when the
126:     // client is started in 'start'. These can be altered
127:     // at any time up to after the 'will_start_client'
128:     // event is finished processing.
129:     public opts: IStartClientOpts = {
130:         initialSyncLimit: 20,
131:     };
132: 
133:     private matrixClient: MatrixClient = null;
134:     private justRegisteredUserId: string | null = null;
135: 
136:     // the credentials used to init the current client object.
137:     // used if we tear it down & recreate it with a different store
138:     private currentClientCreds: IMatrixClientCreds;
139: 
140:     public get(): MatrixClient {
141:         return this.matrixClient;
142:     }
143: 
144:     public unset(): void {
145:         this.matrixClient = null;
146: 
147:         MatrixActionCreators.stop();
148:     }
149: 
150:     public setJustRegisteredUserId(uid: string | null): void {
151:         this.justRegisteredUserId = uid;
152:         if (uid) {
153:             const registrationTime = Date.now().toString();
154:             window.localStorage.setItem("mx_registration_time", registrationTime);
155:         }
156:     }
157: 
158:     public currentUserIsJustRegistered(): boolean {
159:         return this.matrixClient && this.matrixClient.credentials.userId === this.justRegisteredUserId;
160:     }
161: 
162:     public userRegisteredWithinLastHours(hours: number): boolean {
163:         if (hours <= 0) {
164:             return false;
165:         }
166: 
167:         try {
168:             const registrationTime = parseInt(window.localStorage.getItem("mx_registration_time"), 10);
169:             const diff = Date.now() - registrationTime;
170:             return diff / 36e5 <= hours;
171:         } catch (e) {
172:             return false;
173:         }
174:     }
175: 
176:     public userRegisteredAfter(timestamp: Date): boolean {
177:         try {
178:             const registrationTime = parseInt(window.localStorage.getItem("mx_registration_time"), 10);
179:             return timestamp.getTime() <= registrationTime;
180:         } catch (e) {
181:             return false;
182:         }
183:     }
184: 
185:     public replaceUsingCreds(creds: IMatrixClientCreds): void {
186:         this.currentClientCreds = creds;
187:         this.createClient(creds);
188:     }
189: 
190:     public async assign(): Promise<any> {
191:         for (const dbType of ["indexeddb", "memory"]) {
192:             try {
193:                 const promise = this.matrixClient.store.startup();
194:                 logger.log("MatrixClientPeg: waiting for MatrixClient store to initialise");
195:                 await promise;
196:                 break;
197:             } catch (err) {
198:                 if (dbType === "indexeddb") {
199:                     logger.error("Error starting matrixclient store - falling back to memory store", err);
200:                     this.matrixClient.store = new MemoryStore({
201:                         localStorage: localStorage,
202:                     });
203:                 } else {
204:                     logger.error("Failed to start memory store!", err);
205:                     throw err;
206:                 }
207:             }
208:         }
209: 
210:         // try to initialise e2e on the new client
211:         try {
212:             // check that we have a version of the js-sdk which includes initCrypto
213:             if (!SettingsStore.getValue("lowBandwidth") && this.matrixClient.initCrypto) {
214:                 await this.matrixClient.initCrypto();
215:                 this.matrixClient.setCryptoTrustCrossSignedDevices(
216:                     !SettingsStore.getValue("e2ee.manuallyVerifyAllSessions"),
217:                 );
218:                 await tryToUnlockSecretStorageWithDehydrationKey(this.matrixClient);
219:                 StorageManager.setCryptoInitialised(true);
220:             }
221:         } catch (e) {
222:             if (e && e.name === "InvalidCryptoStoreError") {
223:                 // The js-sdk found a crypto DB too new for it to use
224:                 Modal.createDialog(CryptoStoreTooNewDialog);
225:             }
226:             // this can happen for a number of reasons, the most likely being
227:             // that the olm library was missing. It's not fatal.
228:             logger.warn("Unable to initialise e2e", e);
229:         }
230: 
231:         const opts = utils.deepCopy(this.opts);
232:         // the react sdk doesn't work without this, so don't allow
233:         opts.pendingEventOrdering = PendingEventOrdering.Detached;
234:         opts.lazyLoadMembers = true;
235:         opts.clientWellKnownPollPeriod = 2 * 60 * 60; // 2 hours
236:         opts.experimentalThreadSupport = SettingsStore.getValue("feature_thread");
237: 
238:         if (SettingsStore.getValue("feature_sliding_sync")) {
239:             const proxyUrl = SettingsStore.getValue("feature_sliding_sync_proxy_url");
240:             if (proxyUrl) {
241:                 logger.log("Activating sliding sync using proxy at ", proxyUrl);
242:             } else {
243:                 logger.log("Activating sliding sync");
244:             }
245:             opts.slidingSync = SlidingSyncManager.instance.configure(
246:                 this.matrixClient,
247:                 proxyUrl || this.matrixClient.baseUrl,
248:             );
249:             SlidingSyncManager.instance.startSpidering(100, 50); // 100 rooms at a time, 50ms apart
250:         }
251: 
252:         // Connect the matrix client to the dispatcher and setting handlers
253:         MatrixActionCreators.start(this.matrixClient);
254:         MatrixClientBackedSettingsHandler.matrixClient = this.matrixClient;
255: 
256:         return opts;
257:     }
258: 
259:     public async start(): Promise<any> {
260:         const opts = await this.assign();
261: 
262:         logger.log(`MatrixClientPeg: really starting MatrixClient`);
263:         await this.get().startClient(opts);
264:         logger.log(`MatrixClientPeg: MatrixClient started`);
265:     }
266: 
267:     public getCredentials(): IMatrixClientCreds {
268:         let copiedCredentials = this.currentClientCreds;
269:         if (this.currentClientCreds?.userId !== this.matrixClient?.credentials?.userId) {
270:             // cached credentials belong to a different user - don't use them
271:             copiedCredentials = null;
272:         }
273:         return {
274:             // Copy the cached credentials before overriding what we can.
275:             ...(copiedCredentials ?? {}),
276: 
277:             homeserverUrl: this.matrixClient.baseUrl,
278:             identityServerUrl: this.matrixClient.idBaseUrl,
279:             userId: this.matrixClient.credentials.userId,
280:             deviceId: this.matrixClient.getDeviceId(),
281:             accessToken: this.matrixClient.getAccessToken(),
282:             guest: this.matrixClient.isGuest(),
283:         };
284:     }
285: 
286:     public getHomeserverName(): string {
287:         const matches = /^@[^:]+:(.+)$/.exec(this.matrixClient.credentials.userId);
288:         if (matches === null || matches.length < 1) {
289:             throw new Error("Failed to derive homeserver name from user ID!");
290:         }
291:         return matches[1];
292:     }
293: 
294:     private namesToRoomName(names: string[], count: number): string | undefined {
295:         const countWithoutMe = count - 1;
296:         if (!names.length) {
297:             return _t("Empty room");
298:         }
299:         if (names.length === 1 && countWithoutMe <= 1) {
300:             return names[0];
301:         }
302:     }
303: 
304:     private memberNamesToRoomName(names: string[], count: number): string {
305:         const name = this.namesToRoomName(names, count);
306:         if (name) return name;
307: 
308:         if (names.length === 2 && count === 2) {
309:             return _t("%(user1)s and %(user2)s", {
310:                 user1: names[0],
311:                 user2: names[1],
312:             });
313:         }
314:         return _t("%(user)s and %(count)s others", {
315:             user: names[0],
316:             count: count - 1,
317:         });
318:     }
319: 
320:     private inviteeNamesToRoomName(names: string[], count: number): string {
321:         const name = this.namesToRoomName(names, count);
322:         if (name) return name;
323: 
324:         if (names.length === 2 && count === 2) {
325:             return _t("Inviting %(user1)s and %(user2)s", {
326:                 user1: names[0],
327:                 user2: names[1],
328:             });
329:         }
330:         return _t("Inviting %(user)s and %(count)s others", {
331:             user: names[0],
332:             count: count - 1,
333:         });
334:     }
335: 
336:     private createClient(creds: IMatrixClientCreds): void {
337:         const opts: ICreateClientOpts = {
338:             baseUrl: creds.homeserverUrl,
339:             idBaseUrl: creds.identityServerUrl,
340:             accessToken: creds.accessToken,
341:             userId: creds.userId,
342:             deviceId: creds.deviceId,
343:             pickleKey: creds.pickleKey,
344:             timelineSupport: true,
345:             forceTURN: !SettingsStore.getValue("webRtcAllowPeerToPeer"),
346:             fallbackICEServerAllowed: !!SettingsStore.getValue("fallbackICEServerAllowed"),
347:             // Gather up to 20 ICE candidates when a call arrives: this should be more than we'd
348:             // ever normally need, so effectively this should make all the gathering happen when
349:             // the call arrives.
350:             iceCandidatePoolSize: 20,
351:             verificationMethods: [
352:                 verificationMethods.SAS,
353:                 SHOW_QR_CODE_METHOD,
354:                 verificationMethods.RECIPROCATE_QR_CODE,
355:             ],
356:             identityServer: new IdentityAuthClient(),
357:             // These are always installed regardless of the labs flag so that cross-signing features
358:             // can toggle on without reloading and also be accessed immediately after login.
359:             cryptoCallbacks: { ...crossSigningCallbacks },
360:             roomNameGenerator: (_: string, state: RoomNameState) => {
361:                 switch (state.type) {
362:                     case RoomNameType.Generated:
363:                         switch (state.subtype) {
364:                             case "Inviting":
365:                                 return this.inviteeNamesToRoomName(state.names, state.count);
366:                             default:
367:                                 return this.memberNamesToRoomName(state.names, state.count);
368:                         }
369:                     case RoomNameType.EmptyRoom:
370:                         if (state.oldName) {
371:                             return _t("Empty room (was %(oldName)s)", {
372:                                 oldName: state.oldName,
373:                             });
374:                         } else {
375:                             return _t("Empty room");
376:                         }
377:                     default:
378:                         return null;
379:                 }
380:             },
381:         };
382: 
383:         if (SecurityCustomisations.getDehydrationKey) {
384:             opts.cryptoCallbacks!.getDehydrationKey = SecurityCustomisations.getDehydrationKey;
385:         }
386: 
387:         this.matrixClient = createMatrixClient(opts);
388: 
389:         // we're going to add eventlisteners for each matrix event tile, so the
390:         // potential number of event listeners is quite high.
391:         this.matrixClient.setMaxListeners(500);
392: 
393:         this.matrixClient.setGuest(Boolean(creds.guest));
394: 
395:         const notifTimelineSet = new EventTimelineSet(undefined, {
396:             timelineSupport: true,
397:             pendingEvents: false,
398:         });
399:         // XXX: what is our initial pagination token?! it somehow needs to be synchronised with /sync.
400:         notifTimelineSet.getLiveTimeline().setPaginationToken("", EventTimeline.BACKWARDS);
401:         this.matrixClient.setNotifTimelineSet(notifTimelineSet);
402:     }
403: }
