407:  * using this, as in a multi-account world this will not exist!
408:  */
409: export const MatrixClientPeg: IMatrixClientPeg = new MatrixClientPegClass();
410: 
411: if (!window.mxMatrixClientPeg) {
412:     window.mxMatrixClientPeg = MatrixClientPeg;
