17: import { MatrixEvent } from "matrix-js-sdk/src/models/event";
18: import { EventType, RelationType } from "matrix-js-sdk/src/@types/event";
19: 
20: import SettingsStore from "./settings/SettingsStore";
21: import { IRoomState } from "./components/structures/RoomView";
22: 
23: interface IDiff {
24:     isMemberEvent: boolean;
25:     isJoin?: boolean;
26:     isPart?: boolean;
27:     isDisplaynameChange?: boolean;
28:     isAvatarChange?: boolean;
29: }
30: 
31: function memberEventDiff(ev: MatrixEvent): IDiff {
32:     const diff: IDiff = {
33:         isMemberEvent: ev.getType() === EventType.RoomMember,
34:     };
35: 
36:     // If is not a Member Event then the other checks do not apply, so bail early.
37:     if (!diff.isMemberEvent) return diff;
38: 
39:     const content = ev.getContent();
40:     const prevContent = ev.getPrevContent();
41: 
42:     const isMembershipChanged = content.membership !== prevContent.membership;
43:     diff.isJoin = isMembershipChanged && content.membership === "join";
44:     diff.isPart = isMembershipChanged && content.membership === "leave" && ev.getStateKey() === ev.getSender();
45: 
46:     const isJoinToJoin = !isMembershipChanged && content.membership === "join";
47:     diff.isDisplaynameChange = isJoinToJoin && content.displayname !== prevContent.displayname;
48:     diff.isAvatarChange = isJoinToJoin && content.avatar_url !== prevContent.avatar_url;
49:     return diff;
50: }
51: 
52: /**
53:  * Determines whether the given event should be hidden from timelines.
54:  * @param ev The event
55:  * @param ctx An optional RoomContext to pull cached settings values from to avoid
56:  *     hitting the settings store
57:  */
58: export default function shouldHideEvent(ev: MatrixEvent, ctx?: IRoomState): boolean {
59:     // Accessing the settings store directly can be expensive if done frequently,
60:     // so we should prefer using cached values if a RoomContext is available
61:     const isEnabled = ctx ? (name) => ctx[name] : (name) => SettingsStore.getValue(name, ev.getRoomId());
62: 
63:     // Hide redacted events
64:     // Deleted events with a thread are always shown regardless of user preference
65:     // to make sure that a thread can be accessible even if the root message is deleted
66:     if (ev.isRedacted() && !isEnabled("showRedactions") && !ev.getThread()) return true;
67: 
68:     // Hide replacement events since they update the original tile (if enabled)
69:     if (ev.isRelation(RelationType.Replace)) return true;
70: 
71:     const eventDiff = memberEventDiff(ev);
72: 
73:     if (eventDiff.isMemberEvent) {
74:         if ((eventDiff.isJoin || eventDiff.isPart) && !isEnabled("showJoinLeaves")) return true;
75:         if (eventDiff.isAvatarChange && !isEnabled("showAvatarChanges")) return true;
76:         if (eventDiff.isDisplaynameChange && !isEnabled("showDisplaynameChanges")) return true;
77:     }
78: 
79:     return false;
80: }
