    }

    const myUserId = MatrixClientPeg.get().getUserId();

    // Check the main room timeline
    const mainTimelineEvents = room.timeline || [];

    // Get read receipt for main timeline
    const mainReadUpToId = room.getEventReadUpTo(myUserId);

    // Special case: if the last event on the main timeline was sent by the current user,
    // don't count it as unread (we can't send read receipts for our own events)
    const mainTimelineLength = mainTimelineEvents.length;
    if (
        mainTimelineLength > 0 &&
        mainTimelineEvents[mainTimelineLength - 1].getSender() === myUserId
    ) {
