        const threads = room.getThreads ? room.getThreads() : [];
        for (const thread of threads) {
            const threadEvents = thread.timeline || [];
            const threadReadUpToId = room.getEventReadUpTo
                ? (() => {
                      // Try to get thread-specific read receipt
                      try {
                          return (thread as any).getEventReadUpTo?.(myUserId) ??
                              room.getEventReadUpTo(myUserId, false);
                      } catch {
                          return room.getEventReadUpTo(myUserId);
                      }
                  })()
                : null;

            if (timelineHasUnread(threadEvents, threadReadUpToId, myUserId)) {
                return true;
            }
        }
        return false;
    }

    // Check if the main read receipt points to a thread event
    // In that case, the main timeline may still have unread messages
    const receiptEvent = mainReadUpToId ? room.findEventById(mainReadUpToId) : null;
    const receiptIsInThread = receiptEvent?.getThread?.() != null;

    // Check the main room timeline for unread messages
    // If the receipt is in a thread, use null so we scan the full main timeline
    const mainTimeline = room.timeline;
    let mainHasUnread = false;

    if (!receiptIsInThread) {
        // Normal main timeline check
        for (let i = mainTimeline.length - 1; i >= 0; --i) {
            const ev = mainTimeline[i];

            if (ev.getId() === mainReadUpToId) {
                mainHasUnread = false;
                break;
            } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
                mainHasUnread = true;
                break;
            }
        }

        // If we didn't find the read receipt, check if there are events that count
        if (mainReadUpToId && !mainHasUnread) {
            // If we didn't hit the receipt, it might be before our local history
            // In that case, check if there are any counting events
            const hasCountingEvents = mainTimeline.some(
                (ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev),
            );
            mainHasUnread = hasCountingEvents && !mainTimeline.some((ev) => ev.getId() === mainReadUpToId);
        } else if (!mainReadUpToId) {
            // No read receipt at all - check for any events
            mainHasUnread = mainTimeline.some((ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev));
        }
    } else {
        // Receipt is in a thread - check the main timeline for any unread events
        // (Since the receipt is thread-specific, all main-timeline events might be unread)
