    }

    if (mainHasUnread) return true;

    // Now check all threads
    const threads = room.getThreads ? room.getThreads() : [];
    for (const thread of threads) {
        const threadTimeline = thread.timeline || [];

        // Get the thread-specific read receipt
        // Threads track their own read receipts
        let threadReadUpToId: string | null = null;
        try {
            threadReadUpToId = (thread as any).getEventReadUpTo?.(myUserId) ?? null;
        } catch {
            threadReadUpToId = null;
        }

        // If no thread-specific receipt, try the room receipt to see if it's for this thread
        if (!threadReadUpToId && receiptIsInThread && receiptEvent?.getThread?.()?.id === thread.id) {
            threadReadUpToId = mainReadUpToId;
        }

        // Check if the last event in the thread was sent by the current user
        const lastThreadEvent = threadTimeline[threadTimeline.length - 1];
        if (lastThreadEvent?.getSender() === myUserId) {
            continue;
        }

        for (let i = threadTimeline.length - 1; i >= 0; --i) {
            const ev = threadTimeline[i];

            if (ev.getId() === threadReadUpToId) {
                break; // Thread is read up to here
            } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
                return true; // Found unread in thread
            }
        }

        // If we have no thread receipt and there are events that count, it's unread
        if (!threadReadUpToId && threadTimeline.some((ev) => !shouldHideEvent(ev) && eventTriggersUnreadCount(ev))) {
            return true;
        }
    }

    return false;
}

